1	import Foundation
2	
3	// MARK: - Remaining time formatting
4	
5	private let secondsPerMinute = 60
6	private let secondsPerHour = 3600
7	private let secondsPerDay = 86400
8	
9	/// Formats the remaining time until `resetAt` as a compact string (e.g. "2d 5h 13m").
10	/// Returns `"--"` when `resetAt` cannot be parsed, `"0m"` when the reset date has passed.
11	public func formatRemainingTime(resetAt: ISODate, now: Date) -> String {
12	    guard let resetDate = resetAt.date else { return "--" }
13	    let totalSeconds = Int(resetDate.timeIntervalSince(now))
14	    guard totalSeconds > 0 else { return "0m" }
15	
16	    let days = totalSeconds / secondsPerDay
17	    let hours = (totalSeconds % secondsPerDay) / secondsPerHour
18	    let minutes = (totalSeconds % secondsPerHour) / secondsPerMinute
19	
20	    var parts: [String] = []
21	    if days > 0 { parts.append("\(days)d") }
22	    if hours > 0 { parts.append("\(hours)h") }
23	    if minutes > 0 || parts.isEmpty { parts.append("\(minutes)m") }
24	    return parts.joined(separator: " ")
25	}
26	
27	// MARK: - Theoretical fraction
28	
29	/// Fraction of the time window that has elapsed, clamped to 0...1.
30	/// Returns 0 when `resetAt` cannot be parsed or `windowDuration` is zero.
31	public func theoreticalFraction(resetAt: ISODate, windowDuration: DurationMinutes, now: Date) -> Double {
32	    guard let resetDate = resetAt.date else { return 0 }
33	    let windowSeconds = Double(windowDuration.rawValue) * 60
34	    guard windowSeconds > 0 else { return 0 }
35	    let windowStart = resetDate.addingTimeInterval(-windowSeconds)
36	    let elapsed = now.timeIntervalSince(windowStart)
37	    return min(max(elapsed / windowSeconds, 0), 1)
38	}
39	
40	// MARK: - Reset date formatting
41	
42	/// Formats the reset date relative to `now`:
43	/// - same calendar day → time only ("HH:mm")
44	/// - next calendar day → "tomorrow HH:mm"
45	/// - otherwise → "MMM d, HH:mm"
46	/// Returns "--" when `resetAt` cannot be parsed.
47	public func formatResetDate(_ resetAt: ISODate, now: Date) -> String {
48	    guard let resetDate = resetAt.date else { return "--" }
49	    let calendar = Calendar.current
50	    let today = calendar.startOfDay(for: now)
51	    let resetDay = calendar.startOfDay(for: resetDate)
52	    let timeString = ResetDateFormatting.timeFormatter.string(from: resetDate)
53	    if resetDay == today {
54	        return "@ \(timeString)"
55	    }
56	    let tomorrow = calendar.date(byAdding: .day, value: 1, to: today)!
57	    if resetDay == tomorrow {
58	        return "Tomorrow @ \(timeString)"
59	    }
60	    return ResetDateFormatting.dateTimeFormatter.string(from: resetDate)
61	}
62	
63	// Singletons are safe: only called from @MainActor SwiftUI views
64	private enum ResetDateFormatting {
65	    static let timeFormatter: DateFormatter = {
66	        let f = DateFormatter()
67	        f.dateFormat = "HH:mm"
68	        return f
69	    }()
70	
71	    static let dateTimeFormatter: DateFormatter = {
72	        let f = DateFormatter()
73	        f.dateFormat = "MMM d '@' HH:mm"
74	        return f
75	    }()
76	}
77	
78	// MARK: - Consumption tier
79	
80	/// Severity tiers for consumption ratio (actual / theoretical pace).
81	/// Ordered by severity so `Comparable` yields the worst tier via `max()`.
82	public enum ConsumptionTier: Int, Comparable, Sendable, CaseIterable {
83	    case comfortable  // < 0.7
84	    case onTrack      // [0.7, 0.9)
85	    case approaching  // [0.9, 1.0)
86	    case over         // [1.0, 1.2)
87	    case critical     // [1.2, 1.6)
88	    case exhausted    // >= 1.6
89	
90	    public static func < (lhs: ConsumptionTier, rhs: ConsumptionTier) -> Bool {
91	        lhs.rawValue < rhs.rawValue
92	    }
93	
94	    private static let comfortableUpperBound = 0.7
95	    private static let onTrackUpperBound = 0.9
96	    private static let approachingUpperBound = 1.0
97	    private static let overUpperBound = 1.2
98	    private static let criticalUpperBound = 1.6
99	}
100	
101	/// Maps a consumption ratio to the appropriate severity tier.
102	public func consumptionTier(ratio: Double) -> ConsumptionTier {
103	    switch ratio {
104	    case ..<0.7:       return .comfortable
105	    case ..<0.9:       return .onTrack
106	    case ..<1.0:       return .approaching
107	    case ..<1.2:       return .over
108	    case ..<1.6:       return .critical
109	    default:           return .exhausted
110	    }
111	}
112	
113	/// Computes the consumption ratio: how fast actual usage is relative to theoretical pace.
114	/// Returns `nil` when `theoreticalFraction` is zero or negative (window not started).
115	public func consumptionRatio(actualPercent: UsagePercent, theoreticalFraction: Double) -> Double? {
116	    guard theoreticalFraction > 0 else { return nil }
117	    return Double(actualPercent.rawValue) / (theoreticalFraction * 100.0)
118	}
119	
120	// MARK: - Entry sorting
121	
122	extension Array where Element == VendorUsageEntry {
123	    /// Sorted by vendor name, then active-first within each vendor, then account name.
124	    public func sortedForDisplay() -> [VendorUsageEntry] {
